class Solution:
    def repeatedStringMatch(self, a: str, b: str) -> int:
        if b in a:
            return 1
        k_min = (len(b) + len(a) - 1) // len(a)
        s = a * k_min
        if b in s:
            return k_min
        s = a * (k_min + 1)
        if b in s:
            return k_min + 1
        return -1
